  ('public-health-specialist-moex-01236', 'public-health-specialist', 'public-health-specialist-moex-113-8041b019', 'sub-public-health-specialist-04', NULL, 'single_choice', '一個1：1病例對照研究探討暴露到有機氯農藥和乳癌的關聯，假如使用雙尾檢定，顯著水準 為5%，統計檢定力（power）為90%，要偵測到勝算比（oddsratio）為2的差異，病例組和 對照組各約需230人。下列何者改變，會增加研究所需要的樣本數？', '["統計檢定力設為80%", "顯著水準改為1%", "改為單尾檢定", "欲偵測的勝算比改為2.5"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "d5bdd3295981", "answer_pdf_sha1": "45e351b5915d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生物統計學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
